SELECT u.name AS name, u.email, u.phone AS tel, u.profile_image as profileImg,
t.address AS address,
'' AS address_detail, t.business_registration_num AS bizNum, t.br_file AS authDoc, tc.cert_file AS certFile FROM user u left JOIN trainer t ON u.id = t.user_id left JOIN trainer_certification tc ON t.id=tc.trainer_id WHERE u.id = #{userId}
